private struct DeezerHomeScreen: View {
    var body: some View {
        ZStack(alignment: .bottom) {
            ScrollView {
                VStack(alignment: .leading, spacing: 20) {
                    Text("Bonsoir").font(.system(size: 28, weight: .bold)).foregroundStyle(DeezerTokens.dzTextPrimary).padding(.horizontal)
                    LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 12) {
                        ForEach(DeezerDemoData.recent) { item in
                            DeezerRecentTile(item: item, surface: DeezerTokens.dzSurface1)
                        }
                    }
                    .padding(.horizontal)
                    Text("Récemment joué").font(.system(size: 22, weight: .bold)).foregroundStyle(DeezerTokens.dzTextPrimary).padding(.horizontal)
                    ScrollView(.horizontal, showsIndicators: false) {
                        HStack(spacing: 12) {
                            ForEach(DeezerDemoData.playlists) { pl in
                                VStack(alignment: .leading) {
                                    RoundedRectangle(cornerRadius: 6).fill(pl.color).frame(width: 140, height: 140)
                                    Text(pl.title).font(.system(size: 14, weight: .semibold)).foregroundStyle(DeezerTokens.dzTextPrimary).lineLimit(1)
                                }
                            }
                        }
                        .padding(.horizontal)
                    }
                }
                .padding(.vertical).padding(.bottom, 80)
            }
            .background(DeezerTokens.dzCanvas.ignoresSafeArea())
            DeezerMiniPlayer(accent: DeezerTokens.dzTextPrimary, surface: DeezerTokens.dzSurface1, textPri: DeezerTokens.dzTextPrimary)
        }
    }
}

